#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin >> n;
    vector<char> fruits(n);
    for(int i = 0; i < n; i++) cin >> fruits[i];
    int max_len = 0;
    unordered_map<char, int> char_count;
    int left = 0;
    for(int right = 0; right < n; right++){
        char_count[fruits[right]]++;
        while(char_count.size() > 2){
            char_count[fruits[left]]--;
            if(char_count[fruits[left]] == 0) char_count.erase(fruits[left]);
            left++;
        }
        max_len = max(max_len, right - left + 1);
    }
    cout << max_len << endl;
}
